1	//! Zero-copy no_std SPSC ring buffer over a caller-provided
2	//! memory region, per [notes/ring-buffer-design.md]:
3	//!
4	//! - One `#[repr(C)]` [`Header`] spanning four cache lines
5	//!   (immutable geometry, producer index, consumer index, app
6	//!   user words), followed by M slots of N bytes.
7	//! - Indices are free-running `AtomicU32`s, masked only at slot
8	//!   access; full is `p - c == M`, no sacrificial slot.
9	//! - Messages move in place: the producer writes through a
10	//!   [`WriteSlot`] `&mut T`, the consumer reads through a
11	//!   [`ReadSlot`] `&T` — zerocopy traits bound `T`, no
12	//!   serialization step. Each side reserves at most one slot at
13	//!   a time; the guard holds the endpoint borrow until commit /
14	//!   release (or drop).
15	//!
16	//! [notes/ring-buffer-design.md]: https://github.com/winksaville/zc-ring-x1/blob/main/notes/ring-buffer-design.md
17	
18	#![cfg_attr(not(test), no_std)]
19	
20	use core::marker::PhantomData;
21	use core::mem::{align_of, size_of};
22	use core::sync::atomic::{AtomicU32, Ordering};
23	
24	mod consumer;
25	mod producer;
26	
27	pub use consumer::{Consumer, Empty, ReadSlot};
28	pub use producer::{Full, Producer, WriteSlot};
29	
30	/// Cache-line size the layout is built around.
31	///
32	/// - Slot size must be a multiple of this; slots and the region
33	///   itself must be aligned to it.
34	pub const CACHE_LINE: usize = 64;
35	
36	/// Layout marker written by [`Ring::init`]; rejects foreign
37	/// regions on attach.
38	const MAGIC: u32 = 0x5A43_5231; // "ZCR1"
39	
40	/// Bumped on any change to the region layout.
41	const LAYOUT_VERSION: u32 = 2;
42	
43	/// Number of `AtomicU32` words in the header's app-owned
44	/// `user` line.
45	pub const USER_WORDS: usize = 16;
46	
47	/// Cache-line-aligned wrapper granting its field sole
48	/// ownership of the line.
49	///
50	/// - `repr(align(N))` accepts only an integer literal — it
51	///   cannot name [`CACHE_LINE`] — so the `64` is written out
52	///   and a const assert ties them back together.
53	#[repr(C, align(64))]
54	struct CacheAligned<T>(T);
55	
56	const _: () = assert!(align_of::<CacheAligned<AtomicU32>>() == CACHE_LINE);
57	
58	impl<T> core::ops::Deref for CacheAligned<T> {
59	    type Target = T;
60	    /// Access the wrapped value.
61	    fn deref(&self) -> &T {
62	        &self.0
63	    }
64	}
65	
66	/// Control block at offset 0 of the region — one struct spanning
67	/// four cache lines so each concurrently-written index owns its
68	/// own line.
69	///
70	/// - line 0: geometry, written by [`Ring::init`] with `magic`
71	///   last (`Release`), read-only thereafter. Cold: per-op
72	///   paths use the handles' snapshots.
73	/// - line 1: `producer_idx`, written only by the producer.
74	/// - line 2: `consumer_idx`, written only by the consumer.
75	/// - line 3: `user`, app-owned scratch — last, so an app
76	///   overrun walks into its own slot data, not an index line.
77	/// - Every field is atomic: the region may be mapped by a peer
78	///   at any time, so even "immutable" fields must be free of
79	///   data races. `AtomicU32` has the same layout as `u32`, so
80	///   this does not affect `layout_version`.
81	#[repr(C)]
82	pub struct Header {
83	    /// Layout marker ([`MAGIC`]); stored last by init
84	    /// (`Release`), loaded first by attach (`Acquire`), so a
85	    /// peer that observes it also observes the geometry.
86	    magic: AtomicU32,
87	    /// Layout version ([`LAYOUT_VERSION`]).
88	    layout_version: AtomicU32,
89	    /// Slot size N in bytes — a [`CACHE_LINE`] multiple.
90	    slot_size: AtomicU32,
91	    /// Slot count M — a power of two `<= 2^31`.
92	    capacity: AtomicU32,
93	    /// [`CACHE_LINE`] this region was built with. The line size
94	    /// is a layout parameter (padding, offsets, slot granule),
95	    /// so builds must agree; attach validates it like the rest
96	    /// of the geometry.
97	    cache_line: AtomicU32,
98	    /// Free-running count of messages committed.
99	    producer_idx: CacheAligned<AtomicU32>,
100	    /// Free-running count of messages released.
101	    consumer_idx: CacheAligned<AtomicU32>,
102	    /// App-owned scratch line ([`USER_WORDS`] words): zeroed by
103	    /// init, then never read, written, or interpreted by the
104	    /// crate. See the design doc's "Blocking and user words".
105	    user: CacheAligned<[AtomicU32; USER_WORDS]>,
106	}
107	
108	const _: () = assert!(size_of::<Header>() == 4 * CACHE_LINE);
109	
110	/// Errors from [`Ring::init`] / [`Ring::attach`] region
111	/// validation.
112	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
113	pub enum Error {
114	    /// Region is not [`CACHE_LINE`]-aligned.
115	    Misaligned,
116	    /// Region is smaller than header + slots.
117	    TooSmall,
118	    /// Slot size is zero or not a [`CACHE_LINE`] multiple.
119	    BadSlotSize,
120	    /// Capacity is zero, not a power of two, or `> 2^31`.
121	    BadCapacity,
122	    /// Attach: magic mismatch — not a ring region.
123	    BadMagic,
124	    /// Attach: layout version mismatch.
125	    BadLayoutVersion,
126	    /// Attach: region built with a different [`CACHE_LINE`].
127	    BadCacheLine,
128	}
129	
130	/// A validated view over a ring region; split into the two
131	/// endpoint handles with [`Ring::split`].
132	///
133	/// - Geometry is snapshotted out of the header at
134	///   init/attach: per-op paths never re-read fields a peer
135	///   could scribble on, so a hostile peer can degrade the ring
136	///   to garbage messages or spurious Full/Empty, never to UB.
137	pub struct Ring<'a> {
138	    /// The region's control block.
139	    header: &'a Header,
140	    /// Base of the slot array (offset `size_of::<Header>()`).
141	    slots: *mut u8,
142	    /// Snapshot of `header.slot_size`.
143	    slot_size: u32,
144	    /// Snapshot of `header.capacity`.
145	    capacity: u32,
146	    /// Slot-position mask (`capacity - 1`).
147	    mask: u32,
148	    _region: PhantomData<&'a [u8]>,
149	}
150	
151	impl<'a> Ring<'a> {
152	    /// Initialize a fresh region and return the ring over it.
153	    ///
154	    /// - `slot_size` — N bytes per slot, a [`CACHE_LINE`]
155	    ///   multiple.
156	    /// - `capacity` — M slots, a power of two `<= 2^31`.
157	    /// - The region must be [`CACHE_LINE`]-aligned and at least
158	    ///   `size_of::<Header>() + M * N` bytes.
159	    pub fn init(region: &'a mut [u8], slot_size: u32, capacity: u32) -> Result<Self, Error> {
160	        validate_geometry(slot_size, capacity)?;
161	        let len = region.len();
162	        // Taken exactly once: a second `as_mut_ptr()` would
163	        // retag the slice and invalidate `header` under Stacked
164	        // Borrows (Miri-verified).
165	        let base = region.as_mut_ptr();
166	        let header = header_ptr(base, len)?;
167	        if (len as u64) < region_size(slot_size, capacity) {
168	            return Err(Error::TooSmall);
169	        }
170	        // SAFETY: alignment + room for the Header checked by
171	        // header_ptr; region is exclusively borrowed for 'a;
172	        // any byte pattern is a valid Header (all-atomic
173	        // fields, plain-byte padding).
174	        let header = unsafe { &*header };
175	        header
176	            .layout_version
177	            .store(LAYOUT_VERSION, Ordering::Relaxed);
178	        header.slot_size.store(slot_size, Ordering::Relaxed);
179	        header.capacity.store(capacity, Ordering::Relaxed);
180	        header
181	            .cache_line
182	            .store(CACHE_LINE as u32, Ordering::Relaxed);
183	        header.producer_idx.store(0, Ordering::Relaxed);
184	        header.consumer_idx.store(0, Ordering::Relaxed);
185	        for word in header.user.iter() {
186	            word.store(0, Ordering::Relaxed);
187	        }
188	        // Published last: a peer that pre-mapped the region must
189	        // never observe MAGIC before the geometry it validates.
190	        // (Re-initializing a region a peer is already attached
191	        // to is outside the contract.)
192	        header.magic.store(MAGIC, Ordering::Release);
193	        // SAFETY: in bounds — region.len() >= header + slots.
194	        let slots = unsafe { base.add(size_of::<Header>()) };
195	        Ok(Ring {
196	            header,
197	            slots,
198	            slot_size,
199	            capacity,
200	            mask: capacity - 1,
201	            _region: PhantomData,
202	        })
203	    }
204	
205	    /// Attach to a region another process (or an earlier call)
206	    /// already initialized, validating its header.
207	    ///
208	    /// # Safety
209	    ///
210	    /// - `region` points to `len` bytes of memory that outlive
211	    ///   `'a`, genuinely shared and writable (e.g. a
212	    ///   `MAP_SHARED` mapping).
213	    /// - No other producer attaches if this side will produce;
214	    ///   likewise for the consumer side (SPSC contract).
215	    pub unsafe fn attach(region: *mut u8, len: usize) -> Result<Self, Error> {
216	        let header = header_ptr(region, len)?;
217	        // SAFETY: alignment + room for the Header checked by
218	        // header_ptr; caller guarantees the memory is live and
219	        // shared.
220	        let header = unsafe { &*header };
221	        // Acquire pairs with init's Release store of magic: a
222	        // valid magic means the geometry stores are visible.
223	        if header.magic.load(Ordering::Acquire) != MAGIC {
224	            return Err(Error::BadMagic);
225	        }
226	        if header.layout_version.load(Ordering::Relaxed) != LAYOUT_VERSION {
227	            return Err(Error::BadLayoutVersion);
228	        }
229	        if header.cache_line.load(Ordering::Relaxed) != CACHE_LINE as u32 {
230	            return Err(Error::BadCacheLine);
231	        }
232	        // Snapshot geometry once; per-op paths never re-read it.
233	        let slot_size = header.slot_size.load(Ordering::Relaxed);
234	        let capacity = header.capacity.load(Ordering::Relaxed);
235	        validate_geometry(slot_size, capacity)?;
236	        if (len as u64) < region_size(slot_size, capacity) {
237	            return Err(Error::TooSmall);
238	        }
239	        // SAFETY: in bounds — len >= header + slots.
240	        let slots = unsafe { region.add(size_of::<Header>()) };
241	        Ok(Ring {
242	            header,
243	            slots,
244	            slot_size,
245	            capacity,
246	            mask: capacity - 1,
247	            _region: PhantomData,
248	        })
249	    }
250	
251	    /// Split into the producer and consumer endpoint handles.
252	    ///
253	    /// - Consuming `self` makes each handle exist at most once
254	    ///   per ring per process; cross-process, one producing and
255	    ///   one consuming process is the SPSC contract.
256	    pub fn split(self) -> (Producer<'a>, Consumer<'a>) {
257	        (
258	            Producer::new(
259	                self.header,
260	                self.slots,
261	                self.slot_size,
262	                self.capacity,
263	                self.mask,
264	            ),
265	            Consumer::new(self.header, self.slots, self.slot_size, self.mask),
266	        )
267	    }
268	}
269	
270	/// Validate a region base pointer and cast it to the `Header`
271	/// it must start with; shared by [`Ring::init`] / [`Ring::attach`].
272	///
273	/// - Checks alignment and room for the `Header` itself. The
274	///   full-geometry length check stays with the caller: init
275	///   knows the geometry from its parameters, attach only after
276	///   reading it from the returned header.
277	/// - Returns a raw pointer — no deref here. Each caller
278	///   discharges its own safety obligation (init: exclusive
279	///   borrow; attach: the caller's shared-mapping contract).
280	fn header_ptr(base: *mut u8, len: usize) -> Result<*const Header, Error> {
281	    if !(base as usize).is_multiple_of(CACHE_LINE) {
282	        return Err(Error::Misaligned);
283	    }
284	    if len < size_of::<Header>() {
285	        return Err(Error::TooSmall);
286	    }
287	    Ok(base as *const Header)
288	}
289	
290	/// Bytes needed for a region with the given geometry.
291	///
292	/// - Computed in u64: the usize product can wrap on 32-bit
293	///   targets (e.g. N = 2^26, M = 2^6), which would validate a
294	///   tiny region and let safe code write out of bounds.
295	fn region_size(slot_size: u32, capacity: u32) -> u64 {
296	    size_of::<Header>() as u64 + slot_size as u64 * capacity as u64
297	}
298	
299	/// Shared geometry checks for [`Ring::init`] / [`Ring::attach`].
300	fn validate_geometry(slot_size: u32, capacity: u32) -> Result<(), Error> {
301	    if slot_size == 0 || !(slot_size as usize).is_multiple_of(CACHE_LINE) {
302	        return Err(Error::BadSlotSize);
303	    }
304	    // The `> 1 << 31` arm is unreachable (u32 powers of two are
305	    // <= 2^31); it stays to document the M bound the occupancy
306	    // math relies on.
307	    if capacity == 0 || !capacity.is_power_of_two() || capacity > 1 << 31 {
308	        return Err(Error::BadCapacity);
309	    }
310	    Ok(())
311	}
312	
313	/// Check `T` fits a slot; called once per `reserve_slot` (both
314	/// endpoints).
315	///
316	/// - Panics on a type-geometry mismatch — that is a programming
317	///   error, not a runtime condition.
318	fn check_type<T>(slot_size: u32) {
319	    assert!(size_of::<T>() <= slot_size as usize, "T larger than slot");
320	    assert!(
321	        core::mem::align_of::<T>() <= CACHE_LINE,
322	        "T alignment exceeds slot alignment"
323	    );
324	}
325	
326	/// Pointer to the slot for free-running index `idx`.
327	///
328	/// - Returned range is `slot_size` bytes, cache-line aligned
329	///   (base is, and slot_size is a line multiple).
330	fn slot_ptr(slots: *mut u8, idx: u32, mask: u32, slot_size: u32) -> *mut u8 {
331	    let pos = (idx & mask) as usize;
332	    // SAFETY: pos < capacity, so the offset is inside the slot
333	    // array validated at init/attach.
334	    unsafe { slots.add(pos * slot_size as usize) }
335	}
336	
337	#[cfg(test)]
338	mod tests {
339	    use super::*;
340	    use zerocopy::{FromBytes, Immutable, IntoBytes, KnownLayout};
341	
342	    /// Test message; two words so a torn write would be visible.
343	    #[derive(FromBytes, IntoBytes, KnownLayout, Immutable, Debug, PartialEq)]
344	    #[repr(C)]
345	    struct Msg {
346	        seq: u64,
347	        val: u64,
348	    }
349	
350	    /// Test region size: header + (4 slots × 1 line each).
351	    const REGION_BYTES: usize = size_of::<Header>() + (4 * CACHE_LINE);
352	
353	    /// Cache-line-aligned backing store for the tests' rings.
354	    #[repr(C, align(64))]
355	    struct Region([u8; REGION_BYTES]);
356	
357	    impl Region {
358	        fn new() -> Self {
359	            Region([0; REGION_BYTES])
360	        }
361	    }
362	
363	    #[test]
364	    fn init_rejects_bad_geometry() {
365	        let mut r = Region::new();
366	        assert_eq!(
367	            Ring::init(&mut r.0, 63, 4).err().unwrap(),
368	            Error::BadSlotSize
369	        );
370	        assert_eq!(
371	            Ring::init(&mut r.0, 0, 4).err().unwrap(),
372	            Error::BadSlotSize
373	        );
374	        assert_eq!(
375	            Ring::init(&mut r.0, 64, 3).err().unwrap(),
376	            Error::BadCapacity
377	        );
378	        assert_eq!(
379	            Ring::init(&mut r.0, 64, 0).err().unwrap(),
380	            Error::BadCapacity
381	        );
382	        assert_eq!(Ring::init(&mut r.0, 64, 8).err().unwrap(), Error::TooSmall);
383	        assert_eq!(
384	            Ring::init(&mut r.0[1..], 64, 4).err().unwrap(),
385	            Error::Misaligned
386	        );
387	        // 32-bit tripwire: N * M wraps a 32-bit usize (2^26 *
388	        // 2^6 = 2^32); the u64 region_size must still reject it.
389	        assert_eq!(
390	            Ring::init(&mut r.0, 1 << 26, 1 << 6).err().unwrap(),
391	            Error::TooSmall
392	        );
393	    }
394	
395	    #[test]
396	    fn attach_validates_header() {
397	        let mut r = Region::new();
398	        // Not initialized yet: magic is zero.
399	        let err = unsafe { Ring::attach(r.0.as_mut_ptr(), r.0.len()) }
400	            .err()
401	            .unwrap();
402	        assert_eq!(err, Error::BadMagic);
403	        Ring::init(&mut r.0, 64, 4).unwrap();
404	        let ring = unsafe { Ring::attach(r.0.as_mut_ptr(), r.0.len()) }.unwrap();
405	        assert_eq!(ring.slot_size, 64);
406	        assert_eq!(ring.capacity, 4);
407	        assert_eq!(ring.mask, 3);
408	        // A region built with a different CACHE_LINE (simulated
409	        // by editing the recorded value) is rejected.
410	        ring.header.cache_line.store(128, Ordering::Relaxed);
411	        let err = unsafe { Ring::attach(r.0.as_mut_ptr(), r.0.len()) }
412	            .err()
413	            .unwrap();
414	        assert_eq!(err, Error::BadCacheLine);
415	    }
416	
417	    #[test]
418	    fn user_words_zeroed_and_shared() {
419	        let mut r = Region::new();
420	        // Dirty the region so init's zeroing is observable.
421	        r.0.fill(0xAA);
422	        let ring = Ring::init(&mut r.0, 64, 4).unwrap();
423	        let (prod, mut cons) = ring.split();
424	        assert!(prod.user().iter().all(|w| w.load(Ordering::Relaxed) == 0));
425	        // Both endpoints see the same line; a producer-side
426	        // store is visible through the consumer's accessor.
427	        prod.user()[0].store(7, Ordering::Release);
428	        assert_eq!(cons.user()[0].load(Ordering::Acquire), 7);
429	        // The user line must not alias ring state: scribbling
430	        // all of it leaves the ring empty and functional.
431	        for w in cons.user().iter() {
432	            w.store(u32::MAX, Ordering::Relaxed);
433	        }
434	        assert!(cons.reserve_slot::<Msg>().is_err());
435	    }
436	
437	    #[test]
438	    fn indices_survive_u32_wrap() {
439	        let mut r = Region::new();
440	        let ring = Ring::init(&mut r.0, 64, 4).unwrap();
441	        // Simulate a long-running ring two commits shy of the
442	        // u32 wrap (empty state: p == c).
443	        let start = u32::MAX - 1;
444	        ring.header.producer_idx.store(start, Ordering::Relaxed);
445	        ring.header.consumer_idx.store(start, Ordering::Relaxed);
446	        let (mut prod, mut cons) = ring.split();
447	
448	        // Fill: producer_idx runs MAX-1, MAX, 0, 1 — masked
449	        // slot positions 2, 3, 0, 1.
450	        for i in 0..4u64 {
451	            let mut slot = prod.reserve_slot::<Msg>().unwrap();
452	            slot.seq = i;
453	            slot.val = i;
454	            slot.commit();
455	        }
456	        assert!(prod.reserve_slot::<Msg>().is_err());
457	
458	        // Drain in order across the wrap.
459	        for i in 0..4u64 {
460	            let msg = cons.reserve_slot::<Msg>().unwrap();
461	            assert_eq!(msg.seq, i);
462	            msg.release();
463	        }
464	        assert!(cons.reserve_slot::<Msg>().is_err());
465	    }
466	
467	    #[test]
468	    fn roundtrip_full_empty() {
469	        let mut r = Region::new();
470	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
471	
472	        // Empty at start.
473	        assert!(cons.reserve_slot::<Msg>().is_err());
474	
475	        // Fill all 4 slots, then Full.
476	        for i in 0..4u64 {
477	            let mut slot = prod.reserve_slot::<Msg>().unwrap();
478	            slot.seq = i;
479	            slot.val = i * 10;
480	            slot.commit();
481	        }
482	        assert!(prod.reserve_slot::<Msg>().is_err());
483	
484	        // Drain in order; wrap: slot 0 is reused by seq 4.
485	        for i in 0..4u64 {
486	            let msg = cons.reserve_slot::<Msg>().unwrap();
487	            assert_eq!(
488	                *msg,
489	                Msg {
490	                    seq: i,
491	                    val: i * 10
492	                }
493	            );
494	            msg.release();
495	        }
496	        assert!(cons.reserve_slot::<Msg>().is_err());
497	
498	        // One more write lands in the masked-around slot 0.
499	        let mut slot = prod.reserve_slot::<Msg>().unwrap();
500	        slot.seq = 4;
501	        slot.commit();
502	        let msg = cons.reserve_slot::<Msg>().unwrap();
503	        assert_eq!(msg.seq, 4);
504	        msg.release();
505	    }
506	
507	    #[test]
508	    // Dropping the guards is the behavior under test; they have
509	    // no Drop impl by design (abandon = do nothing).
510	    #[allow(clippy::drop_non_drop)]
511	    fn abandoned_guards_publish_nothing() {
512	        let mut r = Region::new();
513	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
514	
515	        // Reserve then drop: nothing published.
516	        let mut slot = prod.reserve_slot::<Msg>().unwrap();
517	        slot.seq = 99;
518	        drop(slot);
519	        assert!(cons.reserve_slot::<Msg>().is_err());
520	
521	        // Commit one, reserve_slot then drop: still unread, the
522	        // next reserve_slot returns it again.
523	        let mut slot = prod.reserve_slot::<Msg>().unwrap();
524	        slot.seq = 1;
525	        slot.commit();
526	        let msg = cons.reserve_slot::<Msg>().unwrap();
527	        assert_eq!(msg.seq, 1);
528	        drop(msg);
529	        let msg = cons.reserve_slot::<Msg>().unwrap();
530	        assert_eq!(msg.seq, 1);
531	        msg.release();
532	    }
533	
534	    #[test]
535	    fn threaded_spsc() {
536	        // Reduced under Miri: interpreted spin loops are slow,
537	        // and its scheduler explores interleavings at any count.
538	        const COUNT: u64 = if cfg!(miri) { 200 } else { 100_000 };
539	        let mut r = Region::new();
540	        let (mut prod, mut cons) = Ring::init(&mut r.0, 64, 4).unwrap().split();
541	
542	        std::thread::scope(|s| {
543	            s.spawn(move || {
544	                for i in 0..COUNT {
545	                    loop {
546	                        match prod.reserve_slot::<Msg>() {
547	                            Ok(mut slot) => {
548	                                slot.seq = i;
549	                                slot.val = i * 3;
550	                                slot.commit();
551	                                break;
552	                            }
553	                            Err(Full) => std::hint::spin_loop(),
554	                        }
555	                    }
556	                }
557	            });
558	            s.spawn(move || {
559	                for i in 0..COUNT {
560	                    loop {
561	                        match cons.reserve_slot::<Msg>() {
562	                            Ok(msg) => {
563	                                assert_eq!(msg.seq, i);
564	                                assert_eq!(msg.val, i * 3);
565	                                msg.release();
566	                                break;
567	                            }
568	                            Err(Empty) => std::hint::spin_loop(),
569	                        }
570	                    }
571	                }
572	            });
573	        });
574	    }
575	}
